var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"뺀질이라뇨! 히로세 교관님이라고 불러 주세요!","ENG":"Don't call me Beomjin! Please address me as Instructor Hirose!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L4_1","type":"dialog","speaker":"MAY_COLLABO_NULL_NULL","text":{"KOREA":"에헤헷. 전적은 아직까지 연습이 더 필요하지만 말이야.","ENG":"Sigh. My record still needs more practice, though."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAY_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L5_1","type":"dialog","speaker":"MAY_COLLABO_NULL_NULL","text":{"KOREA":"앗, 저 사람은……?","ENG":"Ah, who is that...?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAY_COLLABO_NULL_NULL","face":"UNIT_SURPRISE","hologram":false},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L7_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"선글라스 쪽 꼬맹이까지 왔군. 이거 참.","ENG":"Even the brat with sunglasses showed up. Well, well."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAY_COLLABO_NULL_NULL","text":{"KOREA":"꼬맹이라니 너무하잖아. 그렇게 어린애 취급하다간 큰일 날 걸.","ENG":"Calling me a brat is too much. Treat me like a kid like that and you'll be in big trouble."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAY_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L11_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"싸움도 상대를 봐 가면서 걸어라. 꼬마라고 봐 줄 생각 없어.","ENG":"Pick your fights while sizing up your opponent. I have no intention of going easy on you just because you're a kid."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"MAY_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L13_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그래서 저기 비실이 대신 너희들이랑 붙으라고?","ENG":"So instead of that weakling over there, I'm supposed to fight you guys?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"웃기지 마. 훈련이 무슨 애들 장난도 아니고.","ENG":"Don't make me laugh. This training isn't some children's game."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저한테도 질까 봐 겁나는 건 아니고요?","ENG":"Aren't you just scared you might lose to me too?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"누가 겁낸다는 거야?!","ENG":"Who's scared?!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아. 그럼 비실이랑 붙기 전에 너부터 해치워 주지.","ENG":"Fine. Then before I fight that weakling, I'll take you down first."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"잘 보고 있어, 아저씨! 이번에는 안 봐 주고 제대로 할 테니까!","ENG":"Watch closely, old man! This time I won't go easy on you and I'll do it properly!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"그 전에, 가서 세수나 하고 와.","ENG":"Before that, go splash some water on your face."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐?","ENG":"What?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"한 번 졌다고 머리에 피가 너무 쏠렸어. 그 상태로 덤벼 봤자 저 꼬맹이들한테 못 이긴다.","ENG":"You got too much blood rushing to your head after one win. If you charge in like that, you can't beat those brats."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L24_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"여긴 너 혼자 싸우라고 만들어진 곳이 아냐.","ENG":"This isn't a place made for you to fight alone."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L25_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"내가 할 소리까진 아니지만, 조금은 주위를 살펴 보지 그래.","ENG":"It's not my place to say this, but why don't you look around you for once?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L26_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"쳇……. 잔소리나 할 거면 계속 팔짱 끼고 구경이나 해!","ENG":"Tch... If you're just going to nag, keep your arms crossed and just watch!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L28_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장이 말했어. 우린 강하다고.","ENG":"The Captain said so. That we're strong."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS","hologram":false},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"소대에서 제일 앞장서야 할 내가…… 저런 멍청이들한테 꼴사납게 당할 순 없어.","ENG":"I, who should be leading the squad... can't afford to be humiliated by those idiots."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"준비는 끝났어, 꼬맹이들! 실컷 당하고 나서 울지나 말라고!","ENG":"I'm ready, you brats! Don't come crying to me after getting beaten up!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"흐흥, 여기서 싸운 경험은 저 아키가 더 많다고요!","ENG":"Ahem, I, Aki, have more experience fighting here!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE","hologram":false}}}},{"id":"L35_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"가죠! 메이! 이번에야말로 우리도 1승을 챙기는 거예요!","ENG":"Let's go! May! This time we'll finally get our first win!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L36_1","type":"dialog","speaker":"MAY_COLLABO_NULL_NULL","text":{"KOREA":"응! 죠니를 사로잡을 여자가 될 때까지 멈추지 않을 거니까!","ENG":"Yeah! I won't stop until I become the woman who captures Johnny's heart!"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAY_COLLABO_NULL_NULL","face":"UNIT_LAUGH","hologram":false},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L39_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"…….","ENG":"......"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_DESPAIR","hologram":false}}}},{"id":"L40_1","type":"dialog","speaker":"MILLIA_COLLABO_NULL_NULL","text":{"KOREA":"이상하네. 혼자 정리해 버리고 다시는 귀찮게 굴지 말라고 하는 게 당신 스타일 아닌가?","ENG":"How strange. Isn't it your style to handle things alone and tell them not to bother you again?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_DESPAIR","hologram":false}}}},{"id":"L41_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"다 안다는 듯이 떠들지 마라.","ENG":"Don't act like you know everything."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L42_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"반항기의 불량 청소년은 상대 안 해 주는 게 약이야. 어울려 줬다간 멍청함만 배가 돼.","ENG":"The best medicine for a rebellious delinquent is to not engage. If I play along, she'll only become more foolish."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L43_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"그럴 바엔 알아서 머리가 식으라고 내버려 두는 편이 낫지.","ENG":"Better to leave her alone and let her head cool down on its own."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L44_1","type":"dialog","speaker":"MILLIA_COLLABO_NULL_NULL","text":{"KOREA":"당신처럼 말이지?","ENG":"Like you did?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_LAUGH","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L45_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"흥. 한 판 붙고 싶으면 언제든지 덤벼. 그 잘난 머리칼을 통째로 뜯기고 싶으면.","ENG":"Hmph. If you want to fight, come at me anytime. If you want that arrogant hair of yours pulled out whole."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_LAUGH","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L46_1","type":"dialog","speaker":"MILLIA_COLLABO_NULL_NULL","text":{"KOREA":"객관적인 시선으로 내린 평가야. 새겨들어 주면 좋겠는데.","ENG":"It's an evaluation made from an objective perspective. I hope you'll take it to heart."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false}}}},{"id":"L48_1","type":"dialog","speaker":"MILLIA_COLLABO_NULL_NULL","text":{"KOREA":"뭐, 나야 교관으로서 언제까지 막무가내로 날뛰게 둘 수 없는 입장이지만.","ENG":"Well, as an instructor, I can't just let you run rampant indefinitely."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MILLIA_COLLABO_NULL_NULL","text":{"KOREA":"이번에는 내가 함께 싸우겠어. 상관없겠지?","ENG":"This time I'll fight alongside you. You don't mind, right?"},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MILLIA_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOL_COLLABO_NULL_NULL","text":{"KOREA":"……마음대로 해.","ENG":"......Do whatever you want."},"stage":{"bg":"COLLABO_01","bgm":"GUILTY_107","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOL_COLLABO_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}}]`);export{e as default};